sp_widget.client_script:
api.controller = function($scope, $window, $timeout) {
    var c = this;

    c.data = {};
    c.loading = false;

    // Snackbar state
    c.showSnackbar = false;
    c.snackbarMessage = '';
    c.snackbarType = 'success';

    /* SHOW SNACKBAR */
    c.showToast = function(message, type) {
        c.snackbarMessage = message;
        c.snackbarType = type;
        c.showSnackbar = true;

        $timeout(function() {
            c.showSnackbar = false;
        }, 2500);
    };

    /* CONNECT */
    c.connect = function() {

        if (!c.data.connection_name || !c.data.url || !c.data.username || !c.data.password) {
            c.showToast('Please fill all required fields', 'error');
            return;
        }

        c.loading = true;
        c.data.action = "saveConnection";

        c.server.update().then(function(response) {
            c.loading = false;

            if (response.success) {

                // ✅ Show success snackbar
                c.showToast('Connection saved successfully', 'success');

                // ✅ Redirect after delay
                $timeout(function() {
                    $window.location.href = '?id=dm_connection_list';
                }, 1500);

            } else {
                c.showToast(response.error || 'Connection failed', 'error');
            }
        });
    };

    c.goBack = function() {
        $window.location.href = '?id=dm_connection_list';
    };

};

sp_widget.css:
.sp-layout {
  display: flex;
  max-height: calc(100vh - 64px);
	position:relative;
  background: linear-gradient(
    to bottom right,
    #ffffff 0%,
    rgba(13, 124, 143, 0.05) 50%,
    rgba(23, 162, 184, 0.10) 100%
  );
}

/* SIDEBAR */
.sidebar-area {
  flex-basis: 260px;
  flex-shrink:0;
  height:100%;
}

/* CONTENT */
.content-area {
  position:relative;
  display: flex;
  flex-direction: column;
  justify-content:flex-start;
  height:100%;
  gap:30px;
  margin: 0px auto;
  overflow-y:auto;
  height:calc(100vh - 64px);
  width: 100%;
  padding: 30px 15%;
}
@media(max-width:1600px){
  .content-area{
  	padding:30px;
  }
}
/* BACK */
.back-link {
  color: #6b7280;
  text-decoration: none;
  font-size: 14px;
}
a.back-link:focus,
a.back-link:active,
a.back-link:focus-visible {
  outline: none !important;
  box-shadow: none !important;
}

/* HERO */
.hero-section {
  text-align: center;
}
.hero-section h1 {
  font-size: 26px;
  font-weight: 600;
}
.hero-section p {
  color: #6b7280;
}

/* INFO */
.info-banner {
  max-width: 520px;
  margin: 0px auto;
  padding: 12px;
  border-radius: 8px;
  background: #eef4ff;
  color: #2d63b8;
  border: 1px solid #dbeafe;
}

/* CARD */
.form-card {
  width: 520px;
  margin: 0px auto;
  background: #fff;
  padding: 30px;
  border-radius: 14px;
  border: 1px solid #e5e7eb;
  box-shadow: 0 8px 20px rgba(0,0,0,0.06);
}

/* HEADER */
.card-header {
  display: flex;
  gap: 10px;
  margin-bottom: 20px;
}
.card-header h3 {
  margin: 0;
  font-size: 18px;
}
.card-header p {
  margin: 0;
  font-size: 13px;
  color: #6b7280;
}

/* FORM */
.form-group {
  margin-bottom: 18px;
}
.form-group label {
  font-size: 13px;
  font-weight: 600;
}

input, select {
  width: 100%;
  padding: 10px;
  border-radius: 8px;
  border: 1px solid #e5e7eb;
  background: #f9fafb;
}

input:focus, select:focus {
  border-color: #3b82f6;
  background: #fff;
  outline: none;
}

/* BUTTONS */
.form-actions {
  display: flex;
  justify-content: space-between;
  margin-top: 20px;
}

.btn-secondary {
  background: #f3f4f6;
  border: none;
  padding: 10px 18px;
  border-radius: 6px;
}

.btn-light {
  background: #e5e7eb;
  border: none;
  padding: 10px 18px;
  border-radius: 6px;
}


.btn-primary {
   background: linear-gradient(to right, #128a9a, #0a5f6d);
  box-shadow: 0 10px 20px rgba(0, 0, 0, 0.2);
  color: #fff;
  border: none;
  padding: 11px 18px;
  border-radius: 10px;
  font-weight: 600;
  cursor: pointer;
  transition: .2s;
}

.btn-primary:hover {
  transform: translateY(-1px);
  box-shadow: 0 8px 20px rgba(27,99,198,.35);
}
button:disabled {
  opacity: 0.6;
  cursor: not-allowed;
}

.dm-snackbar {
  position: fixed;
  bottom: 30px;
  right: 30px;
  min-width: 280px;
  max-width: 350px;
  padding: 16px 20px;
  border-radius: 12px;
  background: #1f2937;
  color: #fff;
  font-size: 14px;
  display: flex;
  align-items: center;
  gap: 10px;

  opacity: 0;
  transform: translateY(20px);
  transition: all 0.3s ease;

  z-index: 9999;
}

.dm-snackbar.show {
  opacity: 1;
  transform: translateY(0);
}

.dm-snackbar.success {
  background: linear-gradient(to right, #10b981, #34d399);
}

.dm-snackbar.error {
  background: linear-gradient(to right, #ef4444, #f87171);
}

.snackbar-content {
  display: flex;
  align-items: center;
  gap: 10px;
}

.snackbar-content i {
  font-size: 18px;
}

sp_widget.script:
(function() {

data.side = $sp.getWidget('dmm_sidebar');


if (input && input.action === "saveConnection") {
    var dup = new GlideRecord('x_sysus_data_mig_0_connection');

    dup.addQuery('url', input.url);
    dup.addQuery('sys_created_by', gs.getUserName());
    dup.query();

    if (dup.next()) {

        data.success = false;
        data.error = "A connection with this URL already exists.";

        return; // stop execution
    }
    /* ================= VALIDATE CONNECTION ================= */

    var connectionResult = validateAndFetchData(
        input.url,
        input.username,
        input.password
    );


    /* ================= SUCCESS CASE ================= */

    if (connectionResult.isValid) {

        var gr = new GlideRecord(
            'x_sysus_data_mig_0_connection'
        );

        gr.initialize();

        gr.name = input.connection_name;
        gr.url = input.url;
        gr.username = input.username;
        gr.password = input.password;
        gr.state = false;

        var sys_id = gr.insert();


        if (sys_id) {

            /* ================= SUCCESS NOTIFICATION ================= */

            var successNotif =
                new GlideRecord(
                    "x_sysus_data_mig_0_notifications"
                );

            successNotif.initialize();

            successNotif.user = gs.getUserID();

            successNotif.title =
                "Connection Created Successfully";

            successNotif.message =
                "Connection \"" +
                input.connection_name +
                "\" was verified and saved.";

            successNotif.priority = "success";

            successNotif.read = false;

            successNotif.insert();


            /* ================= RESPONSE ================= */

            data.success = true;

            data.new_sys_id = sys_id;

            data.message =
                "Connection successful and data verified.";

        }

        else {

            /* ================= SAVE FAILED NOTIFICATION ================= */

            var saveFailNotif =
                new GlideRecord(
                    "x_sysus_data_mig_0_notifications"
                );

            saveFailNotif.initialize();

            saveFailNotif.user = gs.getUserID();

            saveFailNotif.title =
                "Connection Save Failed";

            saveFailNotif.message =
                "Connection verified but failed to save locally.";

            saveFailNotif.priority = "error";

            saveFailNotif.read = false;

            saveFailNotif.insert();


            data.success = false;

            data.error =
                "Connection verified, but failed to save record.";

        }

    }


    /* ================= VALIDATION FAILURE CASE ================= */

    else {

        var failNotif =
            new GlideRecord(
                "x_sysus_data_mig_0_notifications"
            );

        failNotif.initialize();

        failNotif.user = gs.getUserID();

        failNotif.title =
            "Connection Failed";

        failNotif.message =
            "Connection \"" +
            input.connection_name +
            "\" could not be verified. " +
            connectionResult.errorMessage;

        failNotif.priority = "error";

        failNotif.read = false;

        failNotif.insert();


        data.success = false;

        data.error =
            connectionResult.errorMessage;

    }

}



/* ================= VALIDATION FUNCTION ================= */

function validateAndFetchData(
    instanceUrl,
    username,
    password
) {

    var result = {
        isValid: false,
        errorMessage: ""
    };

    try {

        var r = new sn_ws.RESTMessageV2();

        r.setEndpoint(
            instanceUrl +
            '/api/now/table/sys_user?sysparm_limit=1'
        );

        r.setHttpMethod('GET');

        r.setBasicAuth(
            username,
            password
        );

        r.setRequestHeader(
            'Accept',
            'application/json'
        );

        var response = r.execute();

        var responseBody =
            response.getBody();

        var statusCode =
            response.getStatusCode();


        if (statusCode === 200) {

            var parsedData =
                JSON.parse(responseBody);

            if (
                parsedData.result &&
                parsedData.result.length > 0
            ) {

                result.isValid = true;

            }

            else {

                result.errorMessage =
                    "Connected but no records returned.";

            }

        }

        else if (statusCode === 401) {

            result.errorMessage =
                "Authentication failed: Invalid username or password.";

        }

        else {

            result.errorMessage =
                "Connection failed with status code: " +
                statusCode;

        }

    }

    catch (ex) {

        result.errorMessage =
            "Network error: " +
            ex.message;

    }

    return result;

}

})();
